SELECT FROM sys_user su LEFT JOIN sys_role sr ON su.role_id = sr.id
su.status != 0
AND su.real_name LIKE CONCAT('%', #{realName}, '%')
AND su.role_id = #{roleId}
ORDER BY su.id ASC LIMIT #{offset}, #{pageSize}

