UPDATE sys_user
username = #{username}, password = #{password}, real_name = #{realName}, email = #{email}, phone = #{phone}, status = #{status}, role_id = #{roleId}, login_failed_count = #{loginFailedCount}, account_locked = #{accountLocked}, locked_time = #{lockedTime}, last_login_time = #{lastLoginTime}, last_login_ip = #{lastLoginIp}, update_time = NOW()
